export { default as SAnchor } from './anchor.vue';

export type * from '@soybeanjs/headless/anchor';
export type * from './types';

import type { AnchorCompactEmits, AnchorCompactProps, AnchorUiSlot } from '@soybeanjs/headless/anchor';
import type { ClassValue, UiClass } from '@soybeanjs/headless/types';
import type { ThemeColor, ThemeSize } from '@/theme';

/**
 * Additional UI slots for the anchor component.
 */
export type AnchorExtraUiSlot = Exclude<AnchorUiSlot, 'root' | 'link'>;

/**
 * Extended UI class overrides for the Anchor component.
 */
export type AnchorExtendedUi = UiClass<AnchorUiSlot>;

/**
 * Properties for the Anchor component.
 */
export interface AnchorProps extends AnchorCompactProps {
  /**
   * Theme color of the component.
   */
  color?: ThemeColor;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<AnchorExtendedUi>;
  /**
   * Additional class names applied to the root element.
   */
  class?: ClassValue;
  /**
   * Whether sticky.
   */
  sticky?: boolean;
}

/**
 * Events for the Anchor component.
 */
export type AnchorEmits = AnchorCompactEmits;

// @unocss-include
import { scv } from '@soybeanjs/cva';

export const anchorVariants = scv({
  slots: {
    root: 'relative flex flex-col gap-1 text-sm',
    link: [
      'group inline-flex w-full items-center gap-2 rounded-md px-3 py-2 text-muted-foreground outline-none transition-colors',
      'hover:bg-accent/60 hover:text-accent-foreground',
      'focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background',
      'data-[disabled]:pointer-events-none data-[disabled]:opacity-50',
      'data-[state=active]:bg-accent data-[state=active]:text-foreground'
    ],
    sub: 'ms-4 flex flex-col gap-1 border-s border-border/60 ps-3',
    item: 'flex flex-col gap-1',
    indicator: `size-1.5 shrink-0 rounded-full bg-primary opacity-0 transition-opacity group-data-[state=active]:opacity-100`,
    title: 'min-w-0 truncate'
  },
  variants: {
    color: {
      primary: {
        indicator: 'bg-primary',
        link: 'data-[state=active]:bg-primary/10 data-[state=active]:text-primary'
      },
      destructive: {
        indicator: 'bg-destructive',
        link: 'data-[state=active]:bg-destructive/10 data-[state=active]:text-destructive'
      },
      success: {
        indicator: 'bg-success',
        link: 'data-[state=active]:bg-success/10 data-[state=active]:text-success'
      },
      warning: {
        indicator: 'bg-warning',
        link: 'data-[state=active]:bg-warning/10 data-[state=active]:text-warning'
      },
      info: {
        indicator: 'bg-info',
        link: 'data-[state=active]:bg-info/10 data-[state=active]:text-info'
      },
      carbon: {
        indicator: 'bg-carbon',
        link: 'data-[state=active]:bg-carbon/10 data-[state=active]:text-carbon'
      },
      secondary: {
        indicator: 'bg-secondary-foreground/50',
        link: 'data-[state=active]:bg-secondary-foreground/10 data-[state=active]:text-secondary-foreground'
      },
      accent: {
        indicator: 'bg-accent-foreground/50',
        link: 'data-[state=active]:bg-accent-foreground/10 data-[state=active]:text-accent-foreground'
      }
    },
    orientation: {
      vertical: {},
      horizontal: {
        root: 'flex-row flex-wrap items-start gap-2',
        item: 'min-w-36 flex-1',
        sub: 'ms-0 mt-2 border-s-0 border-t ps-0 pt-2'
      }
    },
    size: {
      xs: {
        link: 'px-2 py-1.5 text-3xs'
      },
      sm: {
        link: 'px-2.5 py-1.5 text-2xs'
      },
      md: {
        link: 'px-3 py-2 text-xs'
      },
      lg: {
        link: 'px-3.5 py-2.5 text-sm',
        indicator: 'size-2'
      },
      xl: {
        link: 'px-4 py-3 text-base',
        indicator: 'size-2'
      },
      '2xl': {
        link: 'px-4.5 py-3.5 text-lg',
        indicator: 'size-2'
      }
    },
    sticky: {
      true: {
        root: 'sticky self-start top-[var(--soybean-anchor-offset-top,0px)] max-h-[calc(100vh-var(--soybean-anchor-offset-top,0px))] overflow-auto pe-1'
      },
      false: {}
    }
  },
  defaultVariants: {
    color: 'primary',
    orientation: 'vertical',
    size: 'md',
    sticky: true
  }
});

import type { ThemeSize } from './types';

export const themeSizeMap: Record<ThemeSize, number> = {
  xs: 12,
  sm: 14,
  md: 16,
  lg: 18,
  xl: 20,
  '2xl': 24
};
export const miniSizeMap: Record<ThemeSize, ThemeSize> = {
  xs: 'xs',
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  xl: 'lg',
  '2xl': 'xl'
};

export const themeSizeRatio = Object.fromEntries(
  Object.entries(themeSizeMap).map(([key, value]) => [key, value / themeSizeMap.md])
) as Record<ThemeSize, number>;
